/*
 * IoT Serial Communication - C Implementation
 * Reads sensor data from Arduino via serial port
 * Compatible with Linux/Unix systems
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <termios.h>
#include <errno.h>

#define SERIAL_PORT "/dev/ttyUSB0"
#define BAUD_RATE B115200
#define BUFFER_SIZE 256
#define MAX_READINGS 100

/* Sensor data structure */
typedef struct {
 float temperature;
 float humidity;
 int light_level;
 unsigned long timestamp;
} SensorReading;

/* Initialize serial port */
int init_serial(const char *port_name) {
 int fd = open(port_name, O_RDWR | O_NOCTTY | O_NDELAY);

 if (fd == -1) {
 perror("Error opening serial port");
 return -1;
 }

 // Configure port settings
 struct termios options;
 tcgetattr(fd, &options);

 // Set baud rate
 cfsetispeed(&options, BAUD_RATE);
 cfsetospeed(&options, BAUD_RATE);

 // 8 data bits, no parity, 1 stop bit (8N1)
 options.c_cflag &= ~PARENB;
 options.c_cflag &= ~CSTOPB;
 options.c_cflag &= ~CSIZE;
 options.c_cflag |= CS8;
 options.c_cflag |= (CLOCAL | CREAD);

 // Set read timeout
 options.c_cc[VMIN] = 0;
 options.c_cc[VTIME] = 10; // 1 second timeout

 tcsetattr(fd, TCSANOW, &options);

 // Flush buffers
 tcflush(fd, TCIOFLUSH);

 return fd;
}

/* Write command to serial device */
int write_to_serial(int fd, const char *command) {
 int len = strlen(command);
 int written = write(fd, command, len);

 if (written != len) {
 perror("Error writing to serial port");
 return -1;
 }

 // Small delay to allow device to process
 usleep(100000); // 100ms

 return 0;
}

/* Read response from serial device */
int read_from_serial(int fd, char *buffer, int buffer_size) {
 memset(buffer, 0, buffer_size);

 int bytes_read = read(fd, buffer, buffer_size - 1);

 if (bytes_read < 0) {
 if (errno == EAGAIN) {
 return 0; // No data available
 }
 perror("Error reading from serial port");
 return -1;
 }

 return bytes_read;
}

/* Parse sensor data from Arduino JSON format */
int parse_sensor_data(const char *json_str, SensorReading *reading) {
 // Expected format: {"temp":25.5,"humidity":60.2,"light":512}
 // Using simple string parsing (not production-grade JSON parser)

 char temp_str[16], hum_str[16], light_str[16];

 if (sscanf(json_str, "{\"temp\":%15[^,],\"humidity\":%15[^,],\"light\":%15s}",
 temp_str, hum_str, light_str) == 3) {
 reading->temperature = atof(temp_str);
 reading->humidity = atof(hum_str);
 reading->light_level = atoi(light_str);
 reading->timestamp = 0; // Would sync with system time in production
 return 1;
 }

 return 0;
}

/* Process incoming serial data */
void process_serial_data(int fd) {
 char buffer[BUFFER_SIZE];
 SensorReading reading;
 int reading_count = 0;

 printf("Starting sensor data collection...\n");
 printf("----------------------------------------\n");

 // Request sensor data from Arduino
 write_to_serial(fd, "GET_DATA\n");

 while (reading_count < MAX_READINGS) {
 int bytes = read_from_serial(fd, buffer, BUFFER_SIZE);

 if (bytes > 0) {
 // Try to parse the data
 if (parse_sensor_data(buffer, &reading)) {
 printf("[%03d] Temp: %.2f°C | Humidity: %.2f%% | Light: %d\n",
 reading_count + 1,
 reading.temperature,
 reading.humidity,
 reading.light_level);
 reading_count++;

 // Request next reading
 write_to_serial(fd, "GET_DATA\n");
 }
 }

 usleep(500000); // Wait 500ms between readings
 }

 printf("----------------------------------------\n");
 printf("Collected %d sensor readings\n", reading_count);
}

/* Send command to control IoT device */
int send_device_command(int fd, const char *device, const char *command) {
 char buffer[BUFFER_SIZE];

 snprintf(buffer, BUFFER_SIZE, "{\"device\":\"%s\",\"cmd\":\"%s\"}\n", 
 device, command);

 printf("Sending command: %s", buffer);

 return write_to_serial(fd, buffer);
}

/* Calculate statistics from readings */
void calculate_statistics(SensorReading *readings, int count) {
 float temp_sum = 0, hum_sum = 0;
 float temp_min = readings[0].temperature;
 float temp_max = readings[0].temperature;

 for (int i = 0; i < count; i++) {
 temp_sum += readings[i].temperature;
 hum_sum += readings[i].humidity;

 if (readings[i].temperature < temp_min) temp_min = readings[i].temperature;
 if (readings[i].temperature > temp_max) temp_max = readings[i].temperature;
 }

 printf("\n=== Sensor Statistics ===\n");
 printf("Temperature - Avg: %.2f°C | Min: %.2f°C | Max: %.2f°C\n",
 temp_sum / count, temp_min, temp_max);
 printf("Humidity - Average: %.2f%%\n", hum_sum / count);
}

