int main(int argc, char *argv[]) {
 const char *port = (argc > 1) ? argv[1] : SERIAL_PORT;

 printf("IoT Serial Communication Example\n");
 printf("Using serial port: %s\n\n", port);

 // Initialize serial port
 int serial_fd = init_serial(port);

 if (serial_fd < 0) {
 fprintf(stderr, "Failed to initialize serial port\n");
 return 1;
 }

 printf("Serial port initialized successfully\n");

 // Process incoming sensor data
 process_serial_data(serial_fd);

 // Example: Send command to control an LED
 printf("\nSending device control command...\n");
 send_device_command(serial_fd, "led", "on");

 // Close serial port
 close(serial_fd);
 printf("Serial port closed\n");

 return 0;
}
